CREATE TABLE IF NOT EXISTS events (
  id    INTEGER PRIMARY KEY AUTOINCREMENT,
  hid   TEXT NOT NULL,
  ts    INTEGER NOT NULL,
  type  TEXT NOT NULL,
  by    TEXT NOT NULL,
  note  TEXT,
  -- Per-cat scope. 'primary' = the household's first cat (the silent
  -- default for single-cat households). When the firmware learns to
  -- pass per-cat IDs (currently single-cat across the wire), values
  -- will be the stable Cat::id from CatRoster.
  cat   TEXT NOT NULL DEFAULT 'primary',
  -- Idempotency key — 128-bit hex UUID generated by the firmware
  -- and sent on POST /api/feed. Same id replayed (e.g. pending-queue
  -- retry after a network timeout the server actually processed)
  -- silently dedups via the unique index. NULL allowed for legacy
  -- rows from before this column existed.
  event_id TEXT
);
CREATE INDEX        IF NOT EXISTS idx_hid_ts     ON events(hid, ts DESC);
CREATE INDEX        IF NOT EXISTS idx_hid_cat_ts ON events(hid, cat, ts DESC);
CREATE UNIQUE INDEX IF NOT EXISTS idx_event_id   ON events(event_id);

-- ── Households ────────────────────────────────────────────────────
-- One row per household. PIN is required to access the web app
-- and stored as PBKDF2-SHA256(plain_pin, salt, 100k iters). Salt
-- and hash are 32 bytes each (hex-encoded → 64 chars).
CREATE TABLE IF NOT EXISTS households (
  hid        TEXT PRIMARY KEY,
  pin_salt   TEXT NOT NULL,
  pin_hash   TEXT NOT NULL,
  created_at INTEGER NOT NULL
);

-- ── Cats ──────────────────────────────────────────────────────────
-- Mirrors the firmware's CatRoster. slot_id is the stable uint8_t
-- from the device (0..3 today, MAX_CATS=4) — composite PK with hid
-- so multiple households can each have a slot 0. Soft delete via
-- deleted_at preserves event-attribution lookups for cats removed
-- from the active roster.
CREATE TABLE IF NOT EXISTS cats (
  hid                  TEXT NOT NULL,
  slot_id              INTEGER NOT NULL,
  name                 TEXT NOT NULL,
  color                INTEGER NOT NULL DEFAULT 0,         -- 0xRRGGBB; 0 = "auto"
  slug                 TEXT NOT NULL DEFAULT 'C2',
  default_portion_g    INTEGER NOT NULL DEFAULT 40,
  hungry_threshold_sec INTEGER NOT NULL DEFAULT 18000,     -- 5 hours
  deleted_at           INTEGER,                            -- NULL = active
  PRIMARY KEY (hid, slot_id)
);

-- ── Users ─────────────────────────────────────────────────────────
-- Mirrors the firmware's UserRoster. Same composite-PK pattern as
-- cats. Soft delete keeps event `by` attributions stable.
CREATE TABLE IF NOT EXISTS users (
  hid        TEXT NOT NULL,
  slot_id    INTEGER NOT NULL,
  name       TEXT NOT NULL,
  color      INTEGER NOT NULL DEFAULT 0,                   -- 0xRRGGBB; 0 = "auto"
  deleted_at INTEGER,                                      -- NULL = active
  PRIMARY KEY (hid, slot_id)
);

-- ── Migrations ────────────────────────────────────────────────────
-- This file is the CANONICAL FULL SCHEMA — what a brand-new database
-- should look like. For existing databases that need to catch up to
-- the current state, see `migrations/` and the README there.
--
--   migrations/0001_legacy_event_cols.sql  — adds `cat` + `event_id`
--                                            to events for pre-Phase-2
--                                            databases. Skip if the
--                                            DB was created against
--                                            a recent schema.sql.
--   migrations/0002_webapp_tables.sql      — household / cats / users
--                                            tables for the web app.
--
-- Apply old → new with the npm scripts:
--   npm run db:migrate:0001:remote
--   npm run db:migrate:0002:remote
--
-- DON'T run `db:apply:remote` (this file) on an old DB that's missing
-- the events.event_id column — the `CREATE UNIQUE INDEX idx_event_id`
-- below references that column and SQLite will error out. Use the
-- migration files for incremental upgrades.
